mapper.select:
SELECT B1.* FROM ( SELECT A1.*, ROW_NUMBER() OVER ( ORDER BY
requestNo DESC
CAST(A1.${sortColumn} AS INTEGER) ${order}
A1.${sortColumn} ${order}
) AS PAGEINDEX FROM ( SELECT requestMapping.BUSINESS_TYPE_CD AS businessTypeCd, CASE WHEN deployInfo.DEPLOY_NORMAL_YN = 'Y' THEN (SELECT LANG_DESC FROM DOCS_LANG lang WHERE lang.LANG_CD = 'combo.deployType.normalArea' AND lang.LANG_TYPE = #{sessionLang}) WHEN deployInfo.DEPLOY_SPECIAL_YN = 'Y' THEN (SELECT LANG_DESC FROM DOCS_LANG lang WHERE lang.LANG_CD = 'combo.deployType.specialArea' AND lang.LANG_TYPE = #{sessionLang}) ELSE (SELECT LANG_DESC FROM DOCS_LANG lang WHERE lang.LANG_CD = 'combo.deployType.viewing' AND lang.LANG_TYPE = #{sessionLang}) END AS distributeTypeNm, CASE WHEN deployInfo.DEPLOY_NORMAL_YN = 'Y' THEN 'NORMAL' WHEN deployInfo.DEPLOY_SPECIAL_YN = 'Y' THEN 'SPECIAL' ELSE 'VIEWING' END AS distributeTypeCd, request.REQUEST_NO AS requestNo, requestMapping.OBJECT_NO AS objectNo, requestMapping.OBJECT_NM AS drawingNm, requestMapping.REV_NO AS revNo, requestMapping.CURRENT_PAGE_NO AS currentPageNo, requestMapping.TOTAL_PAGE_NO AS totalPageNo, request.REQUEST_PURPOSE AS requestPurpose, FN_GET_CD_NM('requestPurpose', request.REQUEST_PURPOSE::text, #{sessionLang}) AS requestPurposeNm, FN_GET_CD_NM('destroyStatusCd', fileInfo.DESTROY_STATUS_CD::text, #{sessionLang}) AS destroyStatusNm, FN_GET_CD_NM('businessTypeCd', requestMapping.BUSINESS_TYPE_CD::text, #{sessionLang}) AS businessTypeNm, FN_GET_CD_NM('destroyType', fileInfo.DESTROY_TYPE::text, #{sessionLang}) AS destroyTypeNm, acceptUser.USER_CD AS purchaserUserCd, acceptUser.USER_NM AS purchaserUserNm, TO_CHAR(TO_DATE(fileInfo.USE_END_YMD, 'YYYYMMDD'), 'YYYY-MM-DD') AS useEndYmd, request.INSERT_DT AS requestDt, request.APPROVAL_DT AS approvalDt, requestMapping.STD_GAPP_DT AS stdGappDt, requestMapping.CHANGE_GAPP_DT AS changeGappDt, requestMapping.PRODUCT_CD AS productCd, COALESCE(requestMapping.PRODUCT_CD, '') AS productNm, requestMapping.PROTECT_YN AS protectYn, ( SELECT COUNT(*) FROM DOCS_DESTROY_FILE destroyFile WHERE destroyFile.DESTROY_NO = destroyRequest.DESTROY_NO::text ) AS fileCount, companyUser.USER_CD AS companyUserCd, companyUser.USER_NM AS companyUserNm, fileInfo.DESTROY_TYPE AS destroyType, fileInfo.DESTROY_STATUS_CD AS destroyStatusCd, approvalFile.LAST_DESTROY_REQUEST_NO AS lastDestroyRequestNo, fileInfo.ORG_FILE_NM AS fileNm, fileInfo.ORG_FILE_NM AS orgFileNm, fileInfo.FILE_NO AS fileNo, fileInfo.OBJECT_ID AS objectId, fileInfo.DOWNLOAD_COUNT AS downloadCount, request.BUSINESS_AREA_CD AS businessAreaCd, FN_GET_CD_NM('businessAreaCd', request.BUSINESS_AREA_CD::text, #{sessionLang}) AS businessAreaNm, FN_GET_CD_NM('distributeTypeCd', requestMapping.DISTRIBUTE_TYPE_CD::text, 'ko') AS distributeFileType, (SELECT USER_NM FROM DOCS_USER t WHERE t.USER_CD = request.INSERT_USER_CD) AS requestUserNm, ( SELECT USER_NM FROM DOCS_REQUEST_DETAIL requestDetail INNER JOIN DOCS_USER docsUser ON docsUser.USER_CD = requestDetail.ACTUAL_USER_CD WHERE requestDetail.REQUEST_NO = request.REQUEST_NO AND requestDetail.APPROVAL_STATUS_CD = 'ACCEPT' ) AS deployUserNm FROM DOCS_REQUEST request INNER JOIN DOCS_REQUEST_MAPPING requestMapping ON requestMapping.REQUEST_NO = request.REQUEST_NO INNER JOIN DOCS_REQUEST_DEPLOY deployInfo ON deployInfo.REQUEST_NO = request.REQUEST_NO INNER JOIN DOCS_USER companyUser ON companyUser.USER_CD = deployInfo.DEPLOY_USER_CD LEFT JOIN DOCS_APPROVAL_FILE approvalFile ON approvalFile.REQUEST_NO = requestMapping.REQUEST_NO AND approvalFile.OBJECT_ID = requestMapping.OBJECT_ID LEFT JOIN DOCS_DESTROY_REQUEST destroyRequest ON destroyRequest.DESTROY_REQUEST_NO = approvalFile.LAST_DESTROY_REQUEST_NO INNER JOIN DOCS_REQUEST_DETAIL requestDetail ON requestDetail.REQUEST_NO = request.REQUEST_NO AND requestDetail.APPROVAL_STATUS_CD = 'ACCEPT' INNER JOIN DOCS_USER acceptUser ON acceptUser.USER_CD = requestDetail.ORIGINAL_USER_CD INNER JOIN DOCS_REQUEST_FILE fileInfo ON requestMapping.REQUEST_NO = fileInfo.REQUEST_NO AND requestMapping.OBJECT_ID = fileInfo.OBJECT_ID WHERE request.OBJECT_TYPE = 'DRAWING' AND request.VENDOR_ACCEPT_YN = 'Y' AND request.DEPLOY_COMPANY_CD = #{sessionUser.companyCd, jdbcType=VARCHAR} AND request.REQUEST_TYPE = 'DISTRIBUTION' AND request.STATUS_CD = 'APPROVAL'
AND request.INSERT_DT BETWEEN TO_DATE(#{requestStartDt}, 'YYYY-MM-DD') AND TO_DATE(#{requestEndDt}, 'YYYY-MM-DD') + INTERVAL '1 day'
AND fileInfo.USE_END_YMD >= TO_CHAR(CURRENT_DATE - INTERVAL '1 day' * (SELECT SYSTEM_CONFIG_VALUE FROM DOCS_SYSTEM_CONFIG t WHERE t.SYSTEM_CONFIG_GROUP='SYSTEM_CONFIG' AND t.SYSTEM_CONFIG_CD='VALID_TERM'), 'YYYYMMDD') AND fileInfo.USE_END_YMD <= TO_CHAR(CURRENT_DATE, 'YYYYMMDD')
AND useEndYmd < TO_CHAR(CURRENT_DATE, 'YYYY-MM-DD')
ORDER BY ${sortColumn} ${order}
) A1 ) B1 WHERE PAGEINDEX >= 1
AND PAGEINDEX <= #{end} ;

SELECT COUNT(*) AS TOTAL_COUNT FROM ( SELECT A1.* FROM ( SELECT requestMapping.BUSINESS_TYPE_CD AS businessTypeCd, /* 사업구분 */ CASE WHEN deployInfo.DEPLOY_NORMAL_YN = 'Y' THEN (SELECT LANG_DESC FROM DOCS_LANG lang WHERE lang.LANG_CD = 'combo.deployType.normalArea' AND lang.LANG_TYPE = #{sessionLang}) WHEN deployInfo.DEPLOY_SPECIAL_YN = 'Y' THEN (SELECT LANG_DESC FROM DOCS_LANG lang WHERE lang.LANG_CD = 'combo.deployType.specialArea' AND lang.LANG_TYPE = #{sessionLang}) ELSE (SELECT LANG_DESC FROM DOCS_LANG lang WHERE lang.LANG_CD = 'combo.deployType.viewing' AND lang.LANG_TYPE = #{sessionLang}) END AS distributeTypeNm, /* 배포유형 */ CASE WHEN deployInfo.DEPLOY_NORMAL_YN = 'Y' THEN 'NORMAL' WHEN deployInfo.DEPLOY_SPECIAL_YN = 'Y' THEN 'SPECIAL' ELSE 'VIEWING' END AS distributeTypeCd, /* 배포유형_CODE */ request.REQUEST_NO AS requestNo, /* 요청번호 */ requestMapping.OBJECT_NO AS objectNo, /* 도면번호 */ requestMapping.OBJECT_NM AS drawingNm, /* 도면명 */ requestMapping.REV_NO AS revNo, /* REV */ requestMapping.CURRENT_PAGE_NO AS currentPageNo, /* 페이지 */ requestMapping.TOTAL_PAGE_NO AS totalPageNo, /* 총 페이지 */ request.REQUEST_PURPOSE AS requestPurpose, /* 용도 */ FN_GET_CD_NM('requestPurpose', request.REQUEST_PURPOSE, #{sessionLang}) AS requestPurposeNm, FN_GET_CD_NM('destroyStatusCd', fileInfo.DESTROY_STATUS_CD, #{sessionLang}) AS destroyStatusNm, /* 폐기상태 */ FN_GET_CD_NM('businessTypeCd', requestMapping.BUSINESS_TYPE_CD, #{sessionLang}) AS businessTypeNm, FN_GET_CD_NM('destroyType', fileInfo.DESTROY_TYPE, #{sessionLang}) AS destroyTypeNm, acceptUser.USER_CD AS purchaserUserCd, /* 구매담당자 */ acceptUser.USER_NM AS purchaserUserNm, /* 구매담당자 */ TO_CHAR(TO_DATE(fileInfo.USE_END_YMD, 'YYYYMMDD'), 'YYYY-MM-DD') AS useEndYmd, /* 유효기간 */ request.INSERT_DT AS requestDt, /* 요청일 */ request.APPROVAL_DT AS approvalDt, /* 승인일 */ requestMapping.PRODUCT_CD AS productCd, /* 기종 */ COALESCE(requestMapping.PRODUCT_CD, '') AS productNm, /* 기종 */ requestMapping.PROTECT_YN AS protectYn, /* 방산기술 */ ( SELECT COUNT(*) FROM DOCS_DESTROY_FILE destroyFile WHERE destroyFile.DESTROY_NO = destroyRequest.DESTROY_NO::text ) AS fileCount, companyUser.USER_CD AS companyUserCd, companyUser.USER_NM AS companyUserNm, fileInfo.DESTROY_TYPE AS destroyType, /* 폐기구분 */ fileInfo.DESTROY_STATUS_CD AS destroyStatusCd, approvalFile.LAST_DESTROY_REQUEST_NO AS lastDestroyRequestNo, fileInfo.ORG_FILE_NM AS fileNm, fileInfo.ORG_FILE_NM AS orgFileNm, fileInfo.FILE_NO AS fileNo, fileInfo.OBJECT_ID AS objectId, request.BUSINESS_AREA_CD AS businessAreaCd, FN_GET_CD_NM('businessAreaCd', request.BUSINESS_AREA_CD, #{sessionLang}) AS businessAreaNm, FN_GET_CD_NM('distributeTypeCd', requestMapping.DISTRIBUTE_TYPE_CD, 'ko') AS distributeFileType, (SELECT USER_NM FROM DOCS_USER t WHERE t.USER_CD = request.INSERT_USER_CD) AS requestUserNm, ( SELECT USER_NM FROM DOCS_REQUEST_DETAIL requestDetail INNER JOIN DOCS_USER docsUser ON docsUser.USER_CD = requestDetail.ACTUAL_USER_CD WHERE requestDetail.REQUEST_NO = request.REQUEST_NO AND requestDetail.APPROVAL_STATUS_CD = 'ACCEPT' ) AS deployUserNm /* 배포자 */ FROM DOCS_REQUEST request INNER JOIN DOCS_REQUEST_MAPPING requestMapping ON requestMapping.REQUEST_NO = request.REQUEST_NO INNER JOIN DOCS_REQUEST_DEPLOY deployInfo ON deployInfo.REQUEST_NO = request.REQUEST_NO INNER JOIN DOCS_USER companyUser ON companyUser.USER_CD = deployInfo.DEPLOY_USER_CD LEFT JOIN DOCS_APPROVAL_FILE approvalFile ON approvalFile.REQUEST_NO = requestMapping.REQUEST_NO AND approvalFile.OBJECT_ID = requestMapping.OBJECT_ID LEFT JOIN DOCS_DESTROY_REQUEST destroyRequest ON destroyRequest.DESTROY_REQUEST_NO = approvalFile.LAST_DESTROY_REQUEST_NO INNER JOIN DOCS_REQUEST_DETAIL requestDetail ON requestDetail.REQUEST_NO = request.REQUEST_NO AND requestDetail.APPROVAL_STATUS_CD = 'ACCEPT' INNER JOIN DOCS_USER acceptUser ON acceptUser.USER_CD = requestDetail.ORIGINAL_USER_CD INNER JOIN DOCS_REQUEST_FILE fileInfo ON requestMapping.REQUEST_NO = fileInfo.REQUEST_NO AND requestMapping.OBJECT_ID = fileInfo.OBJECT_ID WHERE request.OBJECT_TYPE = 'DRAWING' AND request.VENDOR_ACCEPT_YN = 'Y' /* 업체에서 배포접수한 대상만 표시 */ AND request.DEPLOY_COMPANY_CD = #{sessionUser.companyCd, jdbcType=VARCHAR} /* 로그인 한 사용자와 같은 회사의 요청 정보만 표시 */ AND request.REQUEST_TYPE = 'DISTRIBUTION' /* 배포요청정보만 표시 */ AND request.STATUS_CD = 'APPROVAL'
AND request.INSERT_DT BETWEEN TO_DATE(#{requestStartDt}, 'YYYY-MM-DD') AND TO_DATE(#{requestEndDt}, 'YYYY-MM-DD') + INTERVAL '1 day'
AND fileInfo.USE_END_YMD >= TO_CHAR(CURRENT_DATE - INTERVAL '1 day' * (SELECT SYSTEM_CONFIG_VALUE FROM DOCS_SYSTEM_CONFIG t WHERE t.SYSTEM_CONFIG_GROUP='SYSTEM_CONFIG' AND t.SYSTEM_CONFIG_CD='VALID_TERM'), 'YYYYMMDD') AND fileInfo.USE_END_YMD <= TO_CHAR(CURRENT_DATE, 'YYYYMMDD')
) A1 WHERE 1=1
AND requestNo = CAST(#{requestNo} AS TEXT)
AND objectNo ILIKE '%' || UPPER(TRIM(#{objectNo})) || '%'
AND drawingNm ILIKE '%' || #{drawingNm} || '%'
AND purchaserUserCd = #{purchaserUserCd}
AND companyUserCd = #{companyUserCd}
AND destroyStatusCd = #{destroyStatusCd}
AND useEndYmd < TO_CHAR(CURRENT_DATE, 'YYYY-MM-DD')
AND businessAreaCd = #{businessAreaCd}
) B1
